import functions_framework
import json


def set_cors_headers(headers=None):
    """Set CORS headers for the response."""
    if headers is None:
        headers = {}
    headers["Access-Control-Allow-Origin"] = "*"
    headers["Access-Control-Allow-Methods"] = "GET, POST, PUT, DELETE, OPTIONS, PATCH"
    headers["Access-Control-Allow-Headers"] = "Content-Type, Authorization, X-Requested-With, Accept, Origin"
    headers["Access-Control-Max-Age"] = "3600"
    return headers


def make_response(data, status_code=200):
    """Create a JSON response with CORS headers."""
    headers = set_cors_headers()
    headers["Content-Type"] = "application/json"
    return (json.dumps(data), status_code, headers)


@functions_framework.http
def main(request):
    """
    HTTP Cloud Function API endpoint with CORS support.
    
    Handles preflight OPTIONS requests and routes to appropriate handlers
    based on HTTP method and path.
    """
    # Handle CORS preflight requests
    if request.method == "OPTIONS":
        headers = set_cors_headers()
        return ("", 204, headers)

    # Parse the path from the request
    path = request.path.strip("/")
    
    # Route requests based on path and method
    try:
        if path == "" or path == "health":
            return handle_health(request)
        elif path == "api/users":
            return handle_users(request)
        elif path.startswith("api/users/"):
            user_id = path.split("/")[-1]
            return handle_user_by_id(request, user_id)
        elif path == "api/items":
            return handle_items(request)
        elif path.startswith("api/items/"):
            item_id = path.split("/")[-1]
            return handle_item_by_id(request, item_id)
        else:
            return make_response(
                {"error": "Not Found", "message": f"Path '/{path}' not found"},
                404
            )
    except Exception as e:
        return make_response(
            {"error": "Internal Server Error", "message": str(e)},
            500
        )


def handle_health(request):
    """Health check endpoint."""
    return make_response({
        "status": "healthy",
        "service": "web-app-api",
        "version": "1.0.0"
    })


def handle_users(request):
    """Handle /api/users endpoint."""
    if request.method == "GET":
        # Return list of users
        users = [
            {"id": "1", "name": "Alice Johnson", "email": "alice@example.com"},
            {"id": "2", "name": "Bob Smith", "email": "bob@example.com"},
            {"id": "3", "name": "Charlie Brown", "email": "charlie@example.com"},
        ]
        return make_response({"users": users, "total": len(users)})
    
    elif request.method == "POST":
        # Create a new user
        request_json = request.get_json(silent=True)
        if not request_json:
            return make_response(
                {"error": "Bad Request", "message": "Request body must be JSON"},
                400
            )
        
        name = request_json.get("name")
        email = request_json.get("email")
        
        if not name or not email:
            return make_response(
                {"error": "Bad Request", "message": "Both 'name' and 'email' are required"},
                400
            )
        
        new_user = {
            "id": "4",
            "name": name,
            "email": email
        }
        return make_response(
            {"message": "User created successfully", "user": new_user},
            201
        )
    
    else:
        return make_response(
            {"error": "Method Not Allowed", "message": f"Method {request.method} not allowed on /api/users"},
            405
        )


def handle_user_by_id(request, user_id):
    """Handle /api/users/<user_id> endpoint."""
    # Sample user data
    users_db = {
        "1": {"id": "1", "name": "Alice Johnson", "email": "alice@example.com"},
        "2": {"id": "2", "name": "Bob Smith", "email": "bob@example.com"},
        "3": {"id": "3", "name": "Charlie Brown", "email": "charlie@example.com"},
    }
    
    if request.method == "GET":
        user = users_db.get(user_id)
        if not user:
            return make_response(
                {"error": "Not Found", "message": f"User with id '{user_id}' not found"},
                404
            )
        return make_response({"user": user})
    
    elif request.method == "PUT":
        user = users_db.get(user_id)
        if not user:
            return make_response(
                {"error": "Not Found", "message": f"User with id '{user_id}' not found"},
                404
            )
        
        request_json = request.get_json(silent=True)
        if not request_json:
            return make_response(
                {"error": "Bad Request", "message": "Request body must be JSON"},
                400
            )
        
        updated_user = {**user, **request_json, "id": user_id}
        return make_response({"message": "User updated successfully", "user": updated_user})
    
    elif request.method == "PATCH":
        user = users_db.get(user_id)
        if not user:
            return make_response(
                {"error": "Not Found", "message": f"User with id '{user_id}' not found"},
                404
            )
        
        request_json = request.get_json(silent=True)
        if not request_json:
            return make_response(
                {"error": "Bad Request", "message": "Request body must be JSON"},
                400
            )
        
        patched_user = {**user}
        for key, value in request_json.items():
            if key != "id":
                patched_user[key] = value
        
        return make_response({"message": "User patched successfully", "user": patched_user})
    
    elif request.method == "DELETE":
        user = users_db.get(user_id)
        if not user:
            return make_response(
                {"error": "Not Found", "message": f"User with id '{user_id}' not found"},
                404
            )
        return make_response({"message": f"User '{user_id}' deleted successfully"})
    
    else:
        return make_response(
            {"error": "Method Not Allowed", "message": f"Method {request.method} not allowed"},
            405
        )


def handle_items(request):
    """Handle /api/items endpoint."""
    if request.method == "GET":
        # Support query parameters for filtering
        category = request.args.get("category")
        limit = request.args.get("limit", 10, type=int)
        offset = request.args.get("offset", 0, type=int)
        
        items = [
            {"id": "1", "name": "Widget A", "category": "widgets", "price": 9.99},
            {"id": "2", "name": "Gadget B", "category": "gadgets", "price": 24.99},
            {"id": "3", "name": "Widget C", "category": "widgets", "price": 14.99},
            {"id": "4", "name": "Tool D", "category": "tools", "price": 39.99},
            {"id": "5", "name": "Gadget E", "category": "gadgets", "price": 19.99},
        ]
        
        if category:
            items = [item for item in items if item["category"] == category]
        
        total = len(items)
        items = items[offset:offset + limit]
        
        return make_response({
            "items": items,
            "total": total,
            "limit": limit,
            "offset": offset
        })
    
    elif request.method == "POST":
        request_json = request.get_json(silent=True)
        if not request_json:
            return make_response(
                {"error": "Bad Request", "message": "Request body must be JSON"},
                400
            )
        
        name = request_json.get("name")
        category = request_json.get("category")
        price = request_json.get("price")
        
        if not all([name, category, price]):
            return make_response(
                {"error": "Bad Request", "message": "'name', 'category', and 'price' are required"},
                400
            )
        
        new_item = {
            "id": "6",
            "name": name,
            "category": category,
            "price": price
        }
        return make_response(
            {"message": "Item created successfully", "item": new_item},
            201
        )
    
    else:
        return make_response(
            {"error": "Method Not Allowed", "message": f"Method {request.method} not allowed on /api/items"},
            405
        )


